import{_ as t,c as s,o,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.2.9：MCP 附件修复、性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.2.9.md","filePath":"changelog/v1.2.9.md","lastUpdated":1772014034000}'),l={name:"changelog/v1.2.9.md"};function d(n,e,i,h,c,p){return o(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-2-9-mcp-附件修复、性能优化" tabindex="-1">v1.2.9：MCP 附件修复、性能优化 <a class="header-anchor" href="#v1-2-9-mcp-附件修复、性能优化" aria-label="Permalink to “v1.2.9：MCP 附件修复、性能优化”">​</a></h1><p><strong>发布日期</strong>：2026-02-20</p><p>这个版本修复了<strong>MCP 工具附件缺少 ID 的问题</strong>，并进行了多项性能优化。</p><h2 id="🎯-一句话总结" tabindex="-1">🎯 一句话总结 <a class="header-anchor" href="#🎯-一句话总结" aria-label="Permalink to “🎯 一句话总结”">​</a></h2><p>修复 MCP 工具附件 ID 缺失问题；使用原生 structuredClone 提升性能；桌面端恢复设置头部遮罩。</p><hr><h2 id="🐛-问题修复" tabindex="-1">🐛 问题修复 <a class="header-anchor" href="#🐛-问题修复" aria-label="Permalink to “🐛 问题修复”">​</a></h2><h3 id="mcp-工具附件-id-修复" tabindex="-1">MCP 工具附件 ID 修复 <a class="header-anchor" href="#mcp-工具附件-id-修复" aria-label="Permalink to “MCP 工具附件 ID 修复”">​</a></h3><p>MCP 工具的附件现在包含正确的 <code>id</code>、<code>sessionID</code> 和 <code>messageID</code>。</p><p><strong>影响</strong>：之前某些 MCP 工具返回的附件可能无法正确关联到会话，现已修复。</p><hr><h2 id="⚡-性能优化" tabindex="-1">⚡ 性能优化 <a class="header-anchor" href="#⚡-性能优化" aria-label="Permalink to “⚡ 性能优化”">​</a></h2><h3 id="使用原生-structuredclone" tabindex="-1">使用原生 structuredClone <a class="header-anchor" href="#使用原生-structuredclone" aria-label="Permalink to “使用原生 structuredClone”">​</a></h3><p>TUI 现在使用 JavaScript 原生的 <code>structuredClone</code> 替代 remeda 库的 <code>clone</code> 函数。</p><p><strong>收益</strong>：更好的性能和原生支持。</p><hr><h3 id="移除不必要的深拷贝" tabindex="-1">移除不必要的深拷贝 <a class="header-anchor" href="#移除不必要的深拷贝" aria-label="Permalink to “移除不必要的深拷贝”">​</a></h3><p>从会话循环和 LLM 流中移除了不必要的深拷贝操作，提升处理速度。</p><hr><h3 id="测试修复" tabindex="-1">测试修复 <a class="header-anchor" href="#测试修复" aria-label="Permalink to “测试修复”">​</a></h3><p>移除了 LLM 测试中的 User-Agent 断言，修复了测试失败问题。</p><hr><h2 id="🖥️-桌面端更新" tabindex="-1">🖥️ 桌面端更新 <a class="header-anchor" href="#🖥️-桌面端更新" aria-label="Permalink to “🖥️ 桌面端更新”">​</a></h2><h3 id="恢复设置头部遮罩" tabindex="-1">恢复设置头部遮罩 <a class="header-anchor" href="#恢复设置头部遮罩" aria-label="Permalink to “恢复设置头部遮罩”">​</a></h3><p>恢复了桌面端设置界面的头部遮罩显示。</p><hr><h2 id="📊-要不要升级" tabindex="-1">📊 要不要升级？ <a class="header-anchor" href="#📊-要不要升级" aria-label="Permalink to “📊 要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 MCP 工具</td><td>✅ 推荐</td></tr><tr><td>关注性能</td><td>✅ 推荐</td></tr><tr><td>一切正常</td><td>⚪ 可选升级</td></tr></tbody></table><hr><h2 id="⬆️-升级命令" tabindex="-1">⬆️ 升级命令 <a class="header-anchor" href="#⬆️-升级命令" aria-label="Permalink to “⬆️ 升级命令”">​</a></h2>',30),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="📋-技术细节" tabindex="-1">📋 技术细节 <a class="header-anchor" href="#📋-技术细节" aria-label="Permalink to “📋 技术细节”">​</a></h2><details><summary>点击展开原始 Release Notes</summary><h2 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h2><ul><li>Add missing id, sessionID, and messageID to MCP tool attachments (@NatChung)</li><li>Remove unnecessary deep clones from session loop and LLM stream</li><li>Remove User-Agent header assertion from LLM test to fix failing test</li></ul><h2 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h2><ul><li>Use structuredClone instead of remeda&#39;s clone for better performance and native support (@mhart)</li></ul><h2 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h2><ul><li>Restore settings header mask</li></ul><p><strong>Thank you to 2 community contributors:</strong></p><ul><li>@mhart: Use structuredClone instead of remeda&#39;s clone</li><li>@NatChung: fix: add missing id/sessionID/messageID to MCP tool attachments</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const b=t(l,[["render",d]]);export{u as __pageData,b as default};
